import{_ as t,o as e,c as o,a2 as d}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"Random Image API i publiczna galeria","description":"","frontmatter":{},"headers":[],"relativePath":"pl-PL/Other/random-image-api-and-public-gallery.md","filePath":"pl-PL/Other/random-image-api-and-public-gallery.md","lastUpdated":1781962217000}'),i={name:"pl-PL/Other/random-image-api-and-public-gallery.md"};function r(l,a,n,c,p,s){return e(),o("div",null,[...a[0]||(a[0]=[d(`<h1 id="random-image-api-i-publiczna-galeria" tabindex="-1">Random Image API i publiczna galeria <a class="header-anchor" href="#random-image-api-i-publiczna-galeria" aria-label="Permalink to &quot;Random Image API i publiczna galeria&quot;">​</a></h1><p>Obie funkcje konfiguruje się w:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings</span></span></code></pre></div><h2 id="random-image-api" tabindex="-1">Random Image API <a class="header-anchor" href="#random-image-api" aria-label="Permalink to &quot;Random Image API&quot;">​</a></h2><p>Random Image API zwraca jeden losowy plik z wybranych katalogów. Przydaje się do teł strony, rotacji avatarów albo losowych obrazów wywoływanych z zewnętrznych stron.</p><p>Po włączeniu użyj:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/random</span></span></code></pre></div><h2 id="ustawienia-random-image-api" tabindex="-1">Ustawienia Random Image API <a class="header-anchor" href="#ustawienia-random-image-api" aria-label="Permalink to &quot;Ustawienia Random Image API&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Opcja</th><th>Cel</th></tr></thead><tbody><tr><td>Enable</td><td>Włącza lub wyłącza endpoint <code>/random</code>. Po wyłączeniu dostęp jest zabroniony.</td></tr><tr><td>Directories</td><td>Ogranicza katalogi, z których API może korzystać. Katalogi spoza tej listy nie mogą być używane.</td></tr><tr><td>Call demo</td><td>Generuje linki random API gotowe do skopiowania.</td></tr></tbody></table><p>Możesz wybrać wiele katalogów. Jeśli dozwolone są tylko <code>/landscape/</code> i <code>/portrait/</code>, random API może wybierać pliki tylko z tych katalogów i ich podkatalogów.</p><h2 id="parametry-random-image-api" tabindex="-1">Parametry Random Image API <a class="header-anchor" href="#parametry-random-image-api" aria-label="Permalink to &quot;Parametry Random Image API&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Parametr</th><th>Przykład</th><th>Cel</th></tr></thead><tbody><tr><td><code>dir</code></td><td><code>/landscape/</code></td><td>Określa losowany katalog.</td></tr><tr><td><code>content</code></td><td><code>image</code></td><td>Określa typ mediów. Użyj <code>image</code>, <code>video</code>, <code>audio</code> albo kombinacji oddzielonych przecinkami.</td></tr><tr><td><code>orientation</code></td><td><code>auto</code></td><td>Filtruje orientację obrazu. Użyj <code>portrait</code>, <code>landscape</code> albo <code>auto</code>.</td></tr><tr><td><code>type</code></td><td><code>url</code></td><td>Format odpowiedzi. Puste oznacza przekierowanie, <code>url</code> zwraca tekstowy URL, <code>json</code> zwraca JSON.</td></tr><tr><td><code>origin</code></td><td><code>1</code></td><td>Z <code>type=url</code> zwraca pełny URL.</td></tr><tr><td><code>age</code></td><td><code>all-ages,r12</code></td><td>Filtruje według klasyfikacji wiekowej.</td></tr><tr><td><code>tag</code></td><td><code>wallpaper,sky</code></td><td>Zwraca tylko pliki zawierające te tagi.</td></tr><tr><td><code>ex</code></td><td><code>private</code></td><td>Wyklucza pliki zawierające te tagi.</td></tr></tbody></table><h2 id="formaty-odpowiedzi" tabindex="-1">Formaty odpowiedzi <a class="header-anchor" href="#formaty-odpowiedzi" aria-label="Permalink to &quot;Formaty odpowiedzi&quot;">​</a></h2><p>Bez <code>type</code> API przekierowuje bezpośrednio do URL-a losowego pliku.</p><p>Z <code>type=url</code> zwraca URL jako tekst.</p><p>Z <code>type=json</code> zwraca informacje o pliku, w tym URL, ID, nazwę, typ, tagi, rating i powiązane metadane.</p><h2 id="reguły-dostepu" tabindex="-1">Reguły dostępu <a class="header-anchor" href="#reguły-dostepu" aria-label="Permalink to &quot;Reguły dostępu&quot;">​</a></h2><p>Random Image API przestrzega publicznych reguł dostępu:</p><table tabindex="0"><thead><tr><th>Reguła</th><th>Efekt</th></tr></thead><tbody><tr><td>Ograniczenie katalogu</td><td>Wybrane mogą być tylko pliki w dozwolonych katalogach.</td></tr><tr><td>Blocklist</td><td>Pliki z blocklist są wykluczone z puli losowania.</td></tr><tr><td>Tryb allowlist</td><td>Po włączeniu zwracane są tylko pliki dopuszczone do publicznego dostępu.</td></tr><tr><td>Klasyfikacja wiekowa</td><td>R12, R16, R18 i podobne treści są filtrowane według bieżącego trybu dostępu.</td></tr></tbody></table><p>Jeśli po filtrowaniu nie ma pasującego pliku, API nie zwraca wyniku.</p><h2 id="cache" tabindex="-1">Cache <a class="header-anchor" href="#cache" aria-label="Permalink to &quot;Cache&quot;">​</a></h2><p>Random Image API cache&#39;uje pule kandydatów katalogów, aby działać szybciej.</p><p>Po zmianach plików ImgBed aktualizuje wersję cache katalogu, a kolejne żądania odbudowują pulę kandydatów. Puste katalogi są cache&#39;owane krótko, aby uniknąć powtarzanych zapytań.</p><h2 id="publiczna-galeria" tabindex="-1">Publiczna galeria <a class="header-anchor" href="#publiczna-galeria" aria-label="Permalink to &quot;Publiczna galeria&quot;">​</a></h2><p>Publiczna galeria udostępnia odwiedzającym stronę tylko do odczytu dla katalogów, które pozwolisz im oglądać.</p><p>Po włączeniu odwiedzający mogą otworzyć:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/browse/directory-name</span></span></code></pre></div><h2 id="ustawienia-publicznej-galerii" tabindex="-1">Ustawienia publicznej galerii <a class="header-anchor" href="#ustawienia-publicznej-galerii" aria-label="Permalink to &quot;Ustawienia publicznej galerii&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Opcja</th><th>Cel</th></tr></thead><tbody><tr><td>Enable</td><td>Włącza lub wyłącza publiczną galerię. Po wyłączeniu odwiedzający nie mogą jej przeglądać.</td></tr><tr><td>Image loading mode</td><td>Określa, czy podglądy używają oryginalnych obrazów, czy miniatur.</td></tr><tr><td>Open directories</td><td>Ustala, do których katalogów odwiedzający mają dostęp.</td></tr></tbody></table><h2 id="tryb-ładowania-obrazow" tabindex="-1">Tryb ładowania obrazów <a class="header-anchor" href="#tryb-ładowania-obrazow" aria-label="Permalink to &quot;Tryb ładowania obrazów&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tryb</th><th>Cel</th></tr></thead><tbody><tr><td>Original</td><td>Strona odwiedzającego ładuje bezpośrednio oryginalne pliki.</td></tr><tr><td>Thumbnail</td><td>Strona odwiedzającego preferuje miniatury dla szybszego ładowania.</td></tr></tbody></table><h2 id="otwarte-katalogi" tabindex="-1">Otwarte katalogi <a class="header-anchor" href="#otwarte-katalogi" aria-label="Permalink to &quot;Otwarte katalogi&quot;">​</a></h2><p>Otwarte katalogi określają, co widzą odwiedzający.</p><p>Przykład:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/,/2/,/landscape/,/portrait/</span></span></code></pre></div><p>Odwiedzający mogą wtedy otworzyć:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/browse/1</span></span>
<span class="line"><span>https://your-domain.com/browse/2</span></span>
<span class="line"><span>https://your-domain.com/browse/landscape</span></span>
<span class="line"><span>https://your-domain.com/browse/portrait</span></span></code></pre></div><p>Można też otwierać podkatalogi, np. <code>/2026/lucky/</code>. Odwiedzający są blokowani w katalogach, które nie są otwarte.</p><h2 id="funkcje-publicznej-galerii" tabindex="-1">Funkcje publicznej galerii <a class="header-anchor" href="#funkcje-publicznej-galerii" aria-label="Permalink to &quot;Funkcje publicznej galerii&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Funkcja</th><th>Opis</th></tr></thead><tbody><tr><td>Przeglądanie katalogów</td><td>Oglądanie plików i podkatalogów w otwartych katalogach.</td></tr><tr><td>Wyszukiwanie</td><td>Szukanie po nazwie pliku, ID pliku lub tagach.</td></tr><tr><td>Filtr typu</td><td>Filtrowanie obrazów, wideo, audio lub innych plików.</td></tr><tr><td>Filtr tagów</td><td>Uwzględnianie lub wykluczanie wybranych tagów.</td></tr><tr><td>Filtr orientacji</td><td>Filtrowanie obrazów poziomych lub pionowych.</td></tr><tr><td>Filtr czasu</td><td>Filtrowanie według zakresu czasu uploadu.</td></tr><tr><td>Filtr rozszerzenia</td><td>Filtrowanie po rozszerzeniu pliku.</td></tr><tr><td>Kopiowanie linku</td><td>Kopiowanie linków dostępu do plików.</td></tr><tr><td>Podgląd mediów</td><td>Oglądanie lub odtwarzanie obrazów, wideo i audio na stronie odwiedzającego.</td></tr></tbody></table><h2 id="reguły-dostepu-publicznej-galerii" tabindex="-1">Reguły dostępu publicznej galerii <a class="header-anchor" href="#reguły-dostepu-publicznej-galerii" aria-label="Permalink to &quot;Reguły dostępu publicznej galerii&quot;">​</a></h2><p>Publiczna galeria również przestrzega publicznych reguł dostępu:</p><table tabindex="0"><thead><tr><th>Reguła</th><th>Efekt</th></tr></thead><tbody><tr><td>Otwarte katalogi</td><td>Pokazywane są tylko dozwolone katalogi.</td></tr><tr><td>Access mode</td><td>Treści są filtrowane według bieżącego trybu klasyfikacji wiekowej.</td></tr><tr><td>Tryb allowlist</td><td>Po włączeniu pokazywane są tylko pliki dopuszczone do publicznego dostępu.</td></tr><tr><td>Blocklist</td><td>Pliki z blocklist są ukryte.</td></tr></tbody></table>`,43)])])}const b=t(i,[["render",r]]);export{h as __pageData,b as default};
